parameters.jsCode:
/**
 * n8n Code-Node: Parser für Multi-Agent-SaaS
 * Fokus: Bereinigung von Niche-Profiles (Strings & Arrays)
 */

const body = items[0].json.body;

// Hilfsfunktion: Erkennt Strings, Arrays und bereinigt Profile
const processProfile = (input) => {
  if (!input) return null;

  try {
    let rawData;

    // Fall 1: Input ist ein Array (wie in deinem OriginalNicheProfile)
    if (Array.isArray(input)) {
      rawData = input[0];
    } else {
      rawData = input;
    }

    // Falls String: Parsen und korrupte Quotes fixen
    let profile = typeof rawData === 'string' 
      ? JSON.parse(rawData.trim().replace(/^"|"$/g, '')) 
      : rawData;

    // Token-Optimierung: Nur aktive Muster (present: true) behalten
    if (profile.pattern_analysis && Array.isArray(profile.pattern_analysis)) {
      profile.pattern_analysis = profile.pattern_analysis.filter(p => p.present === true);
    }

    // Ballast abwerfen
    delete profile.row_number;
    delete profile["Last Updated"];

    return profile;
  } catch (e) {
    return input; // Fallback bei Fehler
  }
};

// Rückgabe der bereinigten Daten
return [{
  json: {
    execution_id: body.execution_id,
    OriginalNiche: body.OriginalNiche?.replace(/"/g, ''),
    OriginalSlogan: body.OriginalSlogan,
    // Verarbeitete Profile
    OriginalNicheProfile: processProfile(body.OriginalNicheProfile),
    NicheProfileSellingNiches: processProfile(body.NicheProfileSellingNiches)
  }
}];

/**
 * Combined: JSON Parser + Transform to PRODUCT REFERENCE VALIDATION v2.0 LEAN Format
 * 
 * Phase 1: Bereinigt korrupte Anführungszeichen & parsed verschachtelte JSON-Strings
 * Phase 2: Transformiert in LEAN Format für PRODUCT REFERENCE VALIDATION v2.0
 */

const body = items[0].json.body;

// ===== PHASE 1: JSON PARSING & OPTIMIZATION =====

// 1. Hilfsfunktion: Profile bereinigen & filtern
const optimizeProfile = (profileData) => {
  if (!profileData) return null;
  try {
    // Falls String: Parsen und führende/anhängende Quotes entfernen
    let profile = typeof profileData === 'string' 
      ? JSON.parse(profileData.trim().replace(/^"|"$/g, '')) 
      : profileData;

    // Nur aktive Muster behalten (spart massiv Platz)
    if (profile.pattern_analysis && Array.isArray(profile.pattern_analysis)) {
      profile.pattern_analysis = profile.pattern_analysis.filter(p => p.present === true);
    }

    // Unnötigen Ballast entfernen
    delete profile.row_number;
    delete profile["Last Updated"];

    return profile;
  } catch (e) {
    return profileData; // Fallback
  }
};

// 2. Hilfsfunktion: Verschachtelte JSON-Felder im Body parsen
const safeParse = (data) => {
  if (typeof data !== 'string') return data;
  try {
    return JSON.parse(data.trim().replace(/^"|"$/g, ''));
  } catch (e) {
    return data;
  }
};

// Liste der Felder im Body, die oft als String-JSON kommen
const fieldsToParse = [
  'transferability_notes',
  'customer_psychology',
  'sentiment_analysis',
  'vibe',
  'semantic_structure',
  'key_elements',
  'adaptation_examples'
];

// Durchführung des Deep-Parsing
fieldsToParse.forEach(field => {
  if (body[field]) {
    body[field] = safeParse(body[field]);
  }
});

// Bereinigtes Input-Objekt
const cleanedInput = {
  ...body,
  OriginalNiche: body.OriginalNiche?.replace(/"/g, ''),
  OriginalNicheProfile: optimizeProfile(body.OriginalNicheProfile),
  NicheProfileSellingNiches: optimizeProfile(body.NicheProfileSellingNiches),
  OriginalSloganAnalysis: safeParse(body.OriginalSloganAnalysis)
};

// ===== PHASE 2: TRANSFORM TO LEAN FORMAT =====

const nicheProfile = cleanedInput.NicheProfileSellingNiches;
const grund = cleanedInput.grund;

return [{
  json: {
    // 1. PRODUCT
    product: {
      title: cleanedInput.title,
      slogantext: cleanedInput.slogantext
    },

    // 2. PRODUCT_SLOGAN_ANALYSIS
    product_slogan_analysis: {
      emotional_pattern: cleanedInput.emotional_pattern,
      vibe: cleanedInput.vibe,
      tone: cleanedInput.tone,
      adaptation_formula: cleanedInput.adaptation_formula
    },

    // 3. MATCH_CRITERIA
    match_criteria: {
      required_patterns: nicheProfile.pattern_analysis
        .filter(p => p.present === true)
        .map(p => p.name),
      required_energy: grund.emotional_alignment.energy_level,
      required_signal: grund.signal_conversion.target_signal
    },

    // 4. ORIGINAL_CONTEXT
    original_context: {
      original_slogan: cleanedInput.OriginalSlogan,
      original_pattern: cleanedInput.OriginalSloganAnalysis.primary_pattern
    }
  }
}];

